+package tests
+
+import (
+	"testing"
+
+	"github.com/navidrome/navidrome/model"
+)
+
+func TestToAlbumArtist_GenresSortedDescendingAndDedupedByID(t *testing.T) {
+	albums := model.Albums{
+		{
+			Genres: model.Genres{
+				{ID: "g1", Name: "Middle"},
+				{ID: "g2", Name: "Zebra-Old"},
+			},
+		},
+		{
+			Genres: model.Genres{
+				{ID: "g3", Name: "Apple"},
+				{ID: "g2", Name: "Zebra-New"},
+			},
+		},
+	}
+
+	artist := albums.ToAlbumArtist()
+	if len(artist.Genres) != 3 {
+		t.Fatalf("expected 3 genres after dedupe by ID, got %d", len(artist.Genres))
+	}
+	if artist.Genres[0].ID != "g3" || artist.Genres[1].ID != "g2" || artist.Genres[2].ID != "g1" {
+		t.Fatalf("expected descending IDs [g3 g2 g1], got [%s %s %s]", artist.Genres[0].ID, artist.Genres[1].ID, artist.Genres[2].ID)
+	}
+	if artist.Genres[1].Name != "Zebra-Old" {
+		t.Fatalf("expected first sorted occurrence of g2 to be retained, got %q", artist.Genres[1].Name)
+	}
+}
+
+func TestToAlbumArtist_MbzDominantIDTieBreaks(t *testing.T) {
+	t.Run("equal_frequency_last_seen_wins", func(t *testing.T) {
+		albums := model.Albums{
+			{MbzAlbumArtistID: "id1"},
+			{MbzAlbumArtistID: "id2"},
+		}
+		artist := albums.ToAlbumArtist()
+		if artist.MbzArtistID != "id2" {
+			t.Fatalf("expected last-encountered id on tie, got %q", artist.MbzArtistID)
+		}
+	})
+	t.Run("four_album_tie_last_leader_id1", func(t *testing.T) {
+		albums := model.Albums{
+			{MbzAlbumArtistID: "id2"},
+			{MbzAlbumArtistID: "id1"},
+			{MbzAlbumArtistID: "id2"},
+			{MbzAlbumArtistID: "id1"},
+		}
+		artist := albums.ToAlbumArtist()
+		if artist.MbzArtistID != "id1" {
+			t.Fatalf("expected tie-break to last reaching top count (id1), got %q", artist.MbzArtistID)
+		}
+	})
+	t.Run("four_album_registry_example_not_lex_alone", func(t *testing.T) {
+		albums := model.Albums{
+			{MbzAlbumArtistID: "id1"},
+			{MbzAlbumArtistID: "id2"},
+			{MbzAlbumArtistID: "id1"},
+			{MbzAlbumArtistID: "id2"},
+		}
+		artist := albums.ToAlbumArtist()
+		if artist.MbzArtistID != "id2" {
+			t.Fatalf("expected last leader at max tie (id2) per registry example, not lexicographic tie-break (id1); got %q", artist.MbzArtistID)
+		}
+	})
+}
+
+func TestToAlbumArtist_MbzCandidatePool(t *testing.T) {
+	t.Run("empty_strings_not_candidates", func(t *testing.T) {
+		albums := model.Albums{
+			{MbzAlbumArtistID: ""},
+			{MbzAlbumArtistID: ""},
+			{MbzAlbumArtistID: "id1"},
+		}
+		artist := albums.ToAlbumArtist()
+		if artist.MbzArtistID != "id1" {
+			t.Fatalf("expected empty strings skipped, got %q", artist.MbzArtistID)
+		}
+	})
+	t.Run("non_empty_uuid_majority_wins", func(t *testing.T) {
+		albums := model.Albums{
+			{MbzAlbumArtistID: ""},
+			{MbzAlbumArtistID: "00000000-0000-0000-0000-000000000000"},
+			{MbzAlbumArtistID: "00000000-0000-0000-0000-000000000000"},
+			{MbzAlbumArtistID: "id1"},
+		}
+		artist := albums.ToAlbumArtist()
+		if artist.MbzArtistID != "00000000-0000-0000-0000-000000000000" {
+			t.Fatalf("expected non-empty MBZ values to remain candidates, got %q", artist.MbzArtistID)
+		}
+	})
+	t.Run("unknown_literal_majority_wins", func(t *testing.T) {
+		albums := model.Albums{
+			{MbzAlbumArtistID: "[unknown]"},
+			{MbzAlbumArtistID: "[unknown]"},
+			{MbzAlbumArtistID: "id-winner-if-filtered"},
+		}
+		artist := albums.ToAlbumArtist()
+		if artist.MbzArtistID != "[unknown]" {
+			t.Fatalf("expected literal [unknown] counted as non-empty MBID candidate; got %q", artist.MbzArtistID)
+		}
+	})
+}
