+package tests
+
+import (
+	"os"
+	"strings"
+	"testing"
+)
+
+func TestRefresherUsesFixedChunkSize73(t *testing.T) {
+	b, err := os.ReadFile("../scanner/refresher.go")
+	if err != nil {
+		t.Fatalf("failed reading refresher.go: %v", err)
+	}
+	src := string(b)
+	usesInline73 := strings.Contains(src, "BreakUpStringSlice(ids, 73)")
+	usesNamedConstant73 := strings.Contains(src, "BreakUpStringSlice(ids,") &&
+		(strings.Contains(src, "= 73") || strings.Contains(src, "=73"))
+	if !usesInline73 && !usesNamedConstant73 {
+		t.Fatalf("expected chunking to use size 73 (inline or named constant)")
+	}
+}
+
+func TestRefresherFlushMapAppliesChunkingToRefreshCallback(t *testing.T) {
+	b, err := os.ReadFile("../scanner/refresher.go")
+	if err != nil {
+		t.Fatalf("failed reading refresher.go: %v", err)
+	}
+	src := string(b)
+	hasChunkingInsideFlushMap := strings.Contains(src, "if err := refresh(chunk...); err != nil") &&
+		!strings.Contains(src, "if err := refresh(ids...); err != nil")
+	hasChunkedWrapper := strings.Contains(src, "func (f *refresher) refreshArtistsChunked(ids ...string) error") &&
+		strings.Contains(src, "f.refreshArtists(chunk...)")
+	usesInline73 := strings.Contains(src, "BreakUpStringSlice(ids, 73)")
+	usesNamedConstant73 := strings.Contains(src, "BreakUpStringSlice(ids,") &&
+		(strings.Contains(src, "= 73") || strings.Contains(src, "=73"))
+	if hasChunkedWrapper && !(usesInline73 || usesNamedConstant73) {
+		t.Fatalf("expected chunked wrapper to use size 73")
+	}
+	if !hasChunkingInsideFlushMap && !hasChunkedWrapper {
+		t.Fatalf("expected chunking to be applied either inside flushMap or via refreshArtistsChunked wrapper")
+	}
+}
+
+func TestRefresherFlushRoutesArtistUpdatesToRefreshArtists(t *testing.T) {
+	b, err := os.ReadFile("../scanner/refresher.go")
+	if err != nil {
+		t.Fatalf("failed reading refresher.go: %v", err)
+	}
+	src := string(b)
+	usesDirectCallback := strings.Contains(src, "f.flushMap(f.artist, \"artist\", f.refreshArtists)")
+	usesChunkedCallback := strings.Contains(src, "f.flushMap(f.artist, \"artist\", f.refreshArtistsChunked)")
+	if !usesDirectCallback && !usesChunkedCallback {
+		t.Fatalf("expected flush to route artist updates through refreshArtists path (direct or chunked wrapper)")
+	}
+	if strings.Contains(src, "f.ds.Artist(f.ctx).Refresh") {
+		t.Fatalf("legacy ArtistRepository.Refresh path must not be used in flush")
+	}
+}
+
+func TestRefresherRefreshArtistsUsesModelToAlbumArtistAndNoLegacyRefresh(t *testing.T) {
+	b, err := os.ReadFile("../scanner/refresher.go")
+	if err != nil {
+		t.Fatalf("failed reading refresher.go: %v", err)
+	}
+	src := string(b)
+	if !strings.Contains(src, ".ToAlbumArtist()") {
+		t.Fatalf("expected artist aggregation through ToAlbumArtist")
+	}
+	if strings.Contains(src, ".Refresh(") {
+		t.Fatalf("refreshArtists flow must not call legacy Refresh API")
+	}
+
+	ab, err := os.ReadFile("../model/artist.go")
+	if err != nil {
+		t.Fatalf("failed reading artist.go: %v", err)
+	}
+	artistGo := string(ab)
+	if !strings.Contains(artistGo, "type ArtistRepository interface") {
+		t.Fatalf("expected model/artist.go to define ArtistRepository interface")
+	}
+	if strings.Contains(artistGo, "Refresh(ids ...string) error") {
+		t.Fatalf("ArtistRepository must not declare Refresh; use model-level aggregation and Put")
+	}
+}
+
+func TestRefresherRefreshArtistsUsesGroupAndPut(t *testing.T) {
+	b, err := os.ReadFile("../scanner/refresher.go")
+	if err != nil {
+		t.Fatalf("failed reading refresher.go: %v", err)
+	}
+	src := string(b)
+	if !strings.Contains(src, "album_artist_id") {
+		t.Fatalf("expected albums filtered by album_artist_id")
+	}
+	if !strings.Contains(src, "slice.Group") {
+		t.Fatalf("expected albums grouped using slice.Group")
+	}
+	if !strings.Contains(src, "repo.Put(") {
+		t.Fatalf("expected artist persistence through repo.Put")
+	}
+}
